import{_ as c,C as h,o as s,c as p,a5 as a,b as i,w as t,a as o,E as n,a6 as l}from"./chunks/framework.JW9VOlAI.js";const A=JSON.parse('{"title":"api-syncagent","description":"","frontmatter":{},"headers":[],"relativePath":"overview/api-syncagent.md","filePath":"overview/api-syncagent.md"}'),d={name:"overview/api-syncagent.md"};function u(g,e,m,k,b,f){const r=h("Mermaid");return s(),p("div",null,[e[2]||(e[2]=a(`<h1 id="api-syncagent" tabindex="-1">api-syncagent <a class="header-anchor" href="#api-syncagent" aria-label="Permalink to &quot;api-syncagent&quot;">​</a></h1><p>The <strong>api-syncagent</strong> is a Kubernetes controller that publishes CRDs from a service cluster as <a href="/pr-preview/pr-80/concepts/api-export-binding.html">APIExports</a> in kcp, enabling bidirectional synchronization between many kcp workspaces and a single service cluster. It is the <strong>primary, lowest-effort integration path</strong> for bringing existing Kubernetes operators and CRD-based services into the Platform Mesh. If you already run an operator on a Kubernetes cluster (Crossplane, cert-manager, a custom controller), the api-syncagent lets you expose its APIs to Platform Mesh consumers without modifying the operator itself. For non-CRD APIs or scenarios requiring full control over sync logic, see <a href="/pr-preview/pr-80/overview/multi-cluster-runtime.html">multi-cluster-runtime</a> as the alternative approach.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Integrating a CRD-based service into the Platform Mesh through the api-syncagent follows six steps:</p><ol><li><strong>kcp admin creates an APIExport</strong> in a provider workspace, along with credentials (a kubeconfig Secret) for the Sync Agent.</li><li><strong>Service owner configures the agent</strong> with the APIExport name and the API group to publish.</li><li><strong>Agent is deployed via Helm chart</strong> on the service cluster, into the <code>kcp-system</code> namespace.</li><li><strong>Service owner creates PublishedResource objects</strong> on the service cluster, declaring which CRDs to expose.</li><li><strong>Agent converts PublishedResources into APIResourceSchemas</strong> in kcp. Schema names are hash-based and immutable, making changes safe to revert.</li><li><strong>Agent bundles schemas into the APIExport.</strong> kcp provides a virtual workspace endpoint for the export; the agent begins watching for resources across all consumer workspaces that bind to this APIExport. <strong>Bidirectional synchronization starts.</strong></li></ol><p>From this point on, consumers bind to the APIExport from their own workspaces. Bound APIs appear as normal Kubernetes resources (visible via <code>kubectl api-resources</code>) and can be consumed with standard tooling -- <code>kubectl</code>, Helm, GitOps, or any Kubernetes client.</p><h2 id="publishedresource-crd" tabindex="-1">PublishedResource CRD <a class="header-anchor" href="#publishedresource-crd" aria-label="Permalink to &quot;PublishedResource CRD&quot;">​</a></h2><p>The <code>PublishedResource</code> (<code>syncagent.kcp.io/v1alpha1</code>) is the core configuration primitive. It is <strong>cluster-scoped</strong> and <strong>immutable</strong> -- once created, its spec cannot be changed. Immutability prevents cascading disruptions across consumer workspaces that depend on the published schema.</p><p>A minimal PublishedResource requires only the resource <code>kind</code>, <code>apiGroup</code>, and at least one served version:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">syncagent.kcp.io/v1alpha1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">PublishedResource</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  resource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    apiGroup</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cert-manager.io</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Certificate</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    versions</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">v1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  synchronization</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><h3 id="resource-projection" tabindex="-1">Resource Projection <a class="header-anchor" href="#resource-projection" aria-label="Permalink to &quot;Resource Projection&quot;">​</a></h3><p>The <code>.spec.projection</code> field allows you to change how the CRD appears in kcp. You can modify:</p><ul><li><strong>Kind, plural name, short names, categories</strong> -- rename the resource for consumer clarity</li><li><strong>API group and version</strong> -- publish under a different group or version</li><li><strong>Scope</strong> -- publish a cluster-scoped CRD as namespace-scoped in kcp, or vice versa</li></ul><p>This is useful when the CRD&#39;s internal naming does not match the API contract you want to present to consumers.</p><h3 id="filtering" tabindex="-1">Filtering <a class="header-anchor" href="#filtering" aria-label="Permalink to &quot;Filtering&quot;">​</a></h3><p>The <code>.spec.filter</code> field restricts which resources are synchronized:</p><ul><li><strong>Namespace filter</strong> -- sync only resources in specific namespaces on the service cluster</li><li><strong>Label selector</strong> -- sync only resources matching a label expression</li></ul><h3 id="naming-rules" tabindex="-1">Naming Rules <a class="header-anchor" href="#naming-rules" aria-label="Permalink to &quot;Naming Rules&quot;">​</a></h3><p>The <code>.spec.naming</code> field uses <strong>Go template expressions</strong> to control how objects are named on the service cluster. This prevents collisions when multiple consumer workspaces create resources with the same name.</p><ul><li>Default namespace: <code>{{ .ClusterName }}</code> (each kcp workspace gets its own namespace)</li><li>Default name: SHA3-based hash of the original name</li></ul><p>Available template variables: <code>Object</code>, <code>ClusterName</code>, <code>ClusterPath</code>.</p><h3 id="mutations" tabindex="-1">Mutations <a class="header-anchor" href="#mutations" aria-label="Permalink to &quot;Mutations&quot;">​</a></h3><p>The <code>.spec.mutation</code> field transforms resource contents during synchronization. Separate rules can be defined for spec (kcp-to-cluster direction) and status (cluster-to-kcp direction). Supported mutation types:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>CEL expressions</strong></td><td>Evaluate Common Expression Language rules against the object</td></tr><tr><td><strong>Regex patterns</strong></td><td>Pattern-based string replacement on field values</td></tr><tr><td><strong>Go templates</strong></td><td>Template-based transformation with full sprig/v3 function support</td></tr><tr><td><strong>Field deletion</strong></td><td>Remove specific fields during sync</td></tr></tbody></table><h2 id="the-sync-loop" tabindex="-1">The Sync Loop <a class="header-anchor" href="#the-sync-loop" aria-label="Permalink to &quot;The Sync Loop&quot;">​</a></h2><p>The agent performs a <strong>five-phase reconciliation loop</strong> for each synchronized resource. In each cycle, the &quot;remote&quot; object (in kcp) is the source and the &quot;local&quot; object (on the service cluster) is the destination.</p>`,26)),(s(),i(l,null,{default:t(()=>[n(r,{id:"mermaid-180",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22Phase%201%3A%20Find%20Local%20Object%22%5D%20--%3E%20B%5B%22Phase%202%3A%20Handle%20Deletion%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22Phase%203%3A%20Ensure%20Object%20Existence%22%5D%0A%20%20%20%20C%20--%3E%20D%5B%22Phase%204%3A%20Content%20Synchronization%22%5D%0A%20%20%20%20D%20--%3E%20E%5B%22Phase%205%3A%20Sync%20Related%20Resources%22%5D%0A%20%20%20%20E%20--%3E%20F(%5B%22Requeue%22%5D)%0A%20%20%20%20F%20--%3E%20A%0A%0A%20%20%20%20style%20A%20fill%3A%23dbeafe%2Cstroke%3A%233b82f6%2Cstroke-width%3A2px%2Ccolor%3A%231e3a5f%0A%20%20%20%20style%20B%20fill%3A%23fee2e2%2Cstroke%3A%23ef4444%2Cstroke-width%3A2px%2Ccolor%3A%235f1e1e%0A%20%20%20%20style%20C%20fill%3A%23d1fae5%2Cstroke%3A%2310b981%2Cstroke-width%3A2px%2Ccolor%3A%231e5f3a%0A%20%20%20%20style%20D%20fill%3A%23ede9fe%2Cstroke%3A%237c3aed%2Cstroke-width%3A2px%2Ccolor%3A%233b1e5f%0A%20%20%20%20style%20E%20fill%3A%23fef3c7%2Cstroke%3A%23f59f00%2Cstroke-width%3A2px%2Ccolor%3A%235f4b1e%0A%20%20%20%20style%20F%20fill%3A%23f1f5f9%2Cstroke%3A%2394a3b8%2Cstroke-width%3A2px%2Ccolor%3A%23475569%0A%0A%20%20%20%20linkStyle%200%20stroke%3A%233b82f6%2Cstroke-width%3A3px%0A%20%20%20%20linkStyle%201%20stroke%3A%23ef4444%2Cstroke-width%3A3px%0A%20%20%20%20linkStyle%202%20stroke%3A%2310b981%2Cstroke-width%3A3px%0A%20%20%20%20linkStyle%203%20stroke%3A%237c3aed%2Cstroke-width%3A3px%0A%20%20%20%20linkStyle%204%20stroke%3A%23f59f00%2Cstroke-width%3A3px%0A%20%20%20%20linkStyle%205%20stroke%3A%2394a3b8%2Cstroke-width%3A3px%2Cstroke-dasharray%3A5%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[o(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=a('<h3 id="phase-1-find-local-object" tabindex="-1">Phase 1 -- Find Local Object <a class="header-anchor" href="#phase-1-find-local-object" aria-label="Permalink to &quot;Phase 1 -- Find Local Object&quot;">​</a></h3><p>The agent searches the service cluster using <strong>label selectors</strong> that encode the remote cluster name, namespace, and object name. All sync metadata is stored on the service cluster side only, keeping kcp objects clean of implementation details.</p><h3 id="phase-2-handle-deletion" tabindex="-1">Phase 2 -- Handle Deletion <a class="header-anchor" href="#phase-2-handle-deletion" aria-label="Permalink to &quot;Phase 2 -- Handle Deletion&quot;">​</a></h3><p>A <strong>finalizer</strong> on the kcp object prevents orphaned resources. When the source object is deleted in kcp, the agent removes the corresponding local object on the service cluster first, then cleans up the finalizer. This guarantees that service-cluster resources are not left behind.</p><h3 id="phase-3-ensure-object-existence" tabindex="-1">Phase 3 -- Ensure Object Existence <a class="header-anchor" href="#phase-3-ensure-object-existence" aria-label="Permalink to &quot;Phase 3 -- Ensure Object Existence&quot;">​</a></h3><p>If no local object exists, the agent creates one by applying <strong>projection</strong> rules (scope, naming, group transformations), validating the target namespace, and creating the object. If a label conflict arises with an existing object, the agent adopts it by correcting labels rather than failing.</p><h3 id="phase-4-content-synchronization" tabindex="-1">Phase 4 -- Content Synchronization <a class="header-anchor" href="#phase-4-content-synchronization" aria-label="Permalink to &quot;Phase 4 -- Content Synchronization&quot;">​</a></h3><p>The agent patches the local object&#39;s spec from the kcp source. It tracks <strong>prior state</strong> to generate correct patches (avoiding unintended overwrites of fields set by the local operator). If the CRD defines a <strong>status subresource</strong>, the agent syncs status back from the service cluster to kcp.</p><h3 id="phase-5-sync-related-resources" tabindex="-1">Phase 5 -- Sync Related Resources <a class="header-anchor" href="#phase-5-sync-related-resources" aria-label="Permalink to &quot;Phase 5 -- Sync Related Resources&quot;">​</a></h3><p>Any <strong>related resources</strong> (Secrets, ConfigMaps, or other auxiliary objects) are synchronized using the same reconciliation logic. Their state is stored in a single Secret on the service cluster rather than in kcp.</p><h2 id="data-flow-direction" tabindex="-1">Data Flow Direction <a class="header-anchor" href="#data-flow-direction" aria-label="Permalink to &quot;Data Flow Direction&quot;">​</a></h2><p>Despite the PublishedResource CRD describing the world from the <strong>service owner&#39;s perspective</strong> (you &quot;publish&quot; resources from your cluster), the actual data flow is intentionally inverted:</p>',12)),(s(),i(l,null,{default:t(()=>[n(r,{id:"mermaid-217",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20subgraph%20kcp%5B%22kcp%20Workspace%20(Consumer)%22%5D%0A%20%20%20%20%20%20%20%20spec_kcp%5B%22spec%20(desired%20state)%22%5D%0A%20%20%20%20%20%20%20%20status_kcp%5B%22status%20(current%20state)%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20sc%5B%22Service%20Cluster%20(Provider)%22%5D%0A%20%20%20%20%20%20%20%20spec_sc%5B%22spec%22%5D%0A%20%20%20%20%20%20%20%20status_sc%5B%22status%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20spec_kcp%20--%20%22Consumer%20writes%20spec%22%20--%3E%20spec_sc%0A%20%20%20%20status_sc%20--%20%22Provider%20writes%20status%22%20--%3E%20status_kcp%0A%0A%20%20%20%20linkStyle%200%20stroke%3A%234dabf7%2Cstroke-width%3A3px%0A%20%20%20%20linkStyle%201%20stroke%3A%2369db7c%2Cstroke-width%3A3px%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[o(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=a('<ul><li><strong>Spec</strong> flows from kcp to the service cluster. The consumer writes the desired state in their kcp workspace; the agent replicates it to the service cluster where the operator acts on it.</li><li><strong>Status</strong> flows from the service cluster to kcp. The operator on the service cluster updates status as it reconciles; the agent pushes this back to the consumer&#39;s workspace in kcp.</li><li><strong>Related objects</strong> can originate from either side, depending on configuration.</li></ul><p>kcp is always the <strong>authoritative source of truth</strong> for the primary resource&#39;s desired state.</p><h2 id="related-resources" tabindex="-1">Related Resources <a class="header-anchor" href="#related-resources" aria-label="Permalink to &quot;Related Resources&quot;">​</a></h2><p>In practice, most services produce auxiliary Kubernetes objects alongside the primary resource. For example, cert-manager Certificates generate TLS Secrets, and Crossplane creates connection-detail Secrets. The api-syncagent handles these through the <strong>Related Resources</strong> mechanism.</p><h3 id="categories" tabindex="-1">Categories <a class="header-anchor" href="#categories" aria-label="Permalink to &quot;Categories&quot;">​</a></h3><p>Related resources fall into three categories:</p><table tabindex="0"><thead><tr><th>Category</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Core</strong></td><td>Built-in Kubernetes objects</td><td>Secrets, ConfigMaps</td></tr><tr><td><strong>Owned</strong></td><td>Resources defined in the same APIExport</td><td>CRDs managed by the same agent</td></tr><tr><td><strong>Foreign</strong></td><td>Resources from other APIExports</td><td>Requires configuring the identity hash of the foreign APIExport</td></tr></tbody></table><h3 id="object-selection" tabindex="-1">Object Selection <a class="header-anchor" href="#object-selection" aria-label="Permalink to &quot;Object Selection&quot;">​</a></h3><p>Three methods identify which objects are related to a primary resource:</p><ol><li><strong>References</strong> -- JSONPath-like expressions evaluated against both the origin and destination objects, accounting for mutations applied during sync.</li><li><strong>Templates</strong> -- Go template expressions with context variables (<code>Side</code>, <code>Object</code>, <code>ClusterName</code>, <code>ClusterPath</code>).</li><li><strong>Label selectors</strong> -- for cases without direct references. Requires careful naming rules to prevent cross-workspace information leakage.</li></ol><h3 id="permission-claims" tabindex="-1">Permission Claims <a class="header-anchor" href="#permission-claims" aria-label="Permalink to &quot;Permission Claims&quot;">​</a></h3><p>Each related resource <strong>automatically becomes a permission claim</strong> on the APIExport. When a consumer creates an APIBinding, they must explicitly accept these claims. For example, if a published Certificate resource generates Secrets, the APIExport will include a permission claim for <code>secrets</code>. Rejecting namespace access will typically break the service.</p><h2 id="operational-details" tabindex="-1">Operational Details <a class="header-anchor" href="#operational-details" aria-label="Permalink to &quot;Operational Details&quot;">​</a></h2><h3 id="agent-identity-and-naming" tabindex="-1">Agent Identity and Naming <a class="header-anchor" href="#agent-identity-and-naming" aria-label="Permalink to &quot;Agent Identity and Naming&quot;">​</a></h3><p>Each Sync Agent has a unique name (for example, &quot;nora&quot; or &quot;oskar&quot;). Its <strong>fully qualified domain name</strong> is <code>&lt;agentname&gt;.&lt;apigroup&gt;</code> -- for instance, <code>nora.cert-manager.io</code>. One APIExport must be managed by exactly one Sync Agent.</p><h3 id="high-availability" tabindex="-1">High Availability <a class="header-anchor" href="#high-availability" aria-label="Permalink to &quot;High Availability&quot;">​</a></h3><p>Leader election is supported. Multiple replicas of the same agent can run for HA deployments; only the leader actively reconciles.</p><h3 id="multiple-agents-on-one-cluster" tabindex="-1">Multiple Agents on One Cluster <a class="header-anchor" href="#multiple-agents-on-one-cluster" aria-label="Permalink to &quot;Multiple Agents on One Cluster&quot;">​</a></h3><p>Multiple agents can coexist on the same service cluster, provided their PublishedResources are <strong>partitioned by API group</strong>. Use the <code>--published-resource-selector</code> flag or <code>publishedResourceSelector</code> in the Helm values to scope each agent to its designated resources.</p><h3 id="deployment" tabindex="-1">Deployment <a class="header-anchor" href="#deployment" aria-label="Permalink to &quot;Deployment&quot;">​</a></h3><p>The agent is installed via a <strong>Helm chart</strong> into the <code>kcp-system</code> namespace. It requires:</p><ul><li>A <strong>kubeconfig Secret</strong> for connecting to kcp</li><li><strong>RBAC</strong> on the service cluster for the managed resource types</li><li><strong>RBAC</strong> in kcp for APIExports, APIResourceSchemas, and virtual workspace access</li></ul><h3 id="permission-claims-management" tabindex="-1">Permission Claims Management <a class="header-anchor" href="#permission-claims-management" aria-label="Permalink to &quot;Permission Claims Management&quot;">​</a></h3><p>The agent manages the <strong>complete permission claims list</strong> on its APIExport and overwrites it on each reconciliation. This means custom permission claims cannot coexist with agent-managed claims on the same APIExport. Standard claims always include:</p><ul><li><code>events</code> (for surfacing Kubernetes events)</li><li><code>namespaces</code> (for workspace-to-namespace mapping)</li><li><code>core.kcp.io/logicalclusters</code> (when workspace path features are enabled)</li><li>Any resources configured as related resources</li></ul><h2 id="when-to-use-api-syncagent" tabindex="-1">When to Use api-syncagent <a class="header-anchor" href="#when-to-use-api-syncagent" aria-label="Permalink to &quot;When to Use api-syncagent&quot;">​</a></h2><p>The api-syncagent is the right choice when:</p><ul><li>You have an <strong>existing Kubernetes operator</strong> with CRDs that you want to expose in the Platform Mesh</li><li>You want the <strong>lowest integration effort</strong> -- no custom controller code required</li><li>You need <strong>standard bidirectional sync</strong> (spec down, status up) with optional mutations</li><li>Your service produces <strong>related resources</strong> (Secrets, ConfigMaps) that consumers need access to</li></ul><p>Consider <a href="/pr-preview/pr-80/overview/multi-cluster-runtime.html">multi-cluster-runtime</a> instead when:</p><ul><li>Your service exposes <strong>non-CRD APIs</strong> (aggregated API servers, custom API servers)</li><li>You need <strong>full control</strong> over sync logic, conflict resolution, or multi-step orchestration</li><li>Your controller needs to <strong>coordinate state across multiple clusters</strong> rather than mirroring resources</li></ul><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-80/concepts/api-export-binding.html">APIExport and APIBinding</a> -- understand the cross-workspace service sharing mechanism that the api-syncagent builds on</li><li><a href="/pr-preview/pr-80/overview/multi-cluster-runtime.html">multi-cluster-runtime</a> -- the alternative integration path for non-CRD APIs and custom sync logic</li><li><a href="/pr-preview/pr-80/guides/provider-quick-start.html">Provider Quick Start</a> -- step-by-step guide to deploying your first service provider</li><li><a href="/pr-preview/pr-80/guides/httpbin-example.html">HttpBin Provider Example</a> -- a hands-on tutorial walking through a complete api-syncagent integration</li></ul>',32))])}const v=c(d,[["render",u]]);export{A as __pageData,v as default};
